import { Component, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { RouterLink } from '@angular/router';
import { AuthService } from '../../core/services/auth.service';

/**
 * StockRoom signup. The first account on a fresh system becomes a manager
 * (decided server-side); later signups are clerks. On success AuthService
 * redirects home.
 */
@Component({
  selector: 'app-signup',
  standalone: true,
  imports: [CommonModule, FormsModule, RouterLink],
  templateUrl: './signup.component.html',
  styleUrl: './signup.component.css',
})
export class SignupComponent {
  name = '';
  email = '';
  password = '';
  confirm = '';
  readonly submitting = signal(false);
  readonly error = signal<string | null>(null);

  constructor(private auth: AuthService) {}

  submit(): void {
    if (!this.name || !this.email || !this.password) {
      this.error.set('Fill in your name, email and password.');
      return;
    }
    if (this.password !== this.confirm) {
      this.error.set('Passwords do not match.');
      return;
    }
    this.submitting.set(true);
    this.error.set(null);
    this.auth.signup(this.name, this.email, this.password).subscribe({
      error: (err) => {
        this.submitting.set(false);
        this.error.set(err?.error?.message || 'Could not create your account.');
      },
    });
  }
}
